// Copyright 2018 The Go Authors. All rights reserved.// Use of this source code is governed by a BSD-style// license that can be found in the LICENSE file.// Package cpu implements processor feature detection for// various CPU architectures.package cpuimport ("os""strings")// Initialized reports whether the CPU features were initialized.//// For some GOOS/GOARCH combinations initialization of the CPU features depends// on reading an operating specific file, e.g. /proc/self/auxv on linux/arm// Initialized will report false if reading the file fails.var Initialized bool// CacheLinePad is used to pad structs to avoid false sharing.type CacheLinePad struct{ _ [cacheLineSize]byte }// X86 contains the supported CPU features of the// current X86/AMD64 platform. If the current platform// is not X86/AMD64 then all feature flags are false.//// X86 is padded to avoid false sharing. Further the HasAVX// and HasAVX2 are only set if the OS supports XMM and YMM// registers in addition to the CPUID feature bit being set.var X86 struct {_CacheLinePadHasAES bool // AES hardware implementation (AES NI)HasADX bool // Multi-precision add-carry instruction extensionsHasAVX bool // Advanced vector extensionHasAVX2bool // Advanced vector extension 2HasAVX512bool // Advanced vector extension 512HasAVX512Fbool // Advanced vector extension 512 Foundation InstructionsHasAVX512CD extension 512 Conflict Detection InstructionsHasAVX512ER bool //d vectoron 512 Eal and Reciprocal InstructionsHasAVX512PF bool // Advance extension 512 PInstructionsHasAbool // Advanced vectoron 512 Vector Length ExtasAVX512BW bool // Advanor extensiyte and Word InstructionsHasAVX5l // Advanced vector extension 5d Quadword InstructionsHasAVX512IFMAool // Advanced vector extension 512 Inted Multiply AddHasAVX512VBMIbool // Advanced vector extension 512 Vector Byte Manipulation InstructionsHasAVX5124VNNIWbool // Advanced vector extension 512 Vector Neural Network Instructions Word variable precisionHasAVX5124FMAPSbool // Advanced vector extension 512 Fused Multiply Accumulation Packed Single precisionHasAVX512VPOPCNTDQ  bool // Advanced vector extension 512 Double and quad word population count instructionsHasAVX512VPCLMULQDQ bool // Advanced vector extension 512 Vector carry-less multiply operationsHasAVX512VNNIbool // Advanced vector extension 512 Vector Neural Network InstructionsHasAVX512GFNIbool // Advanced vector extension 512 Galois field New InstructionsHasAVX512VAESbool // Advanced vector extension 512 Vector AES instructionsHasAVX512VBMI2bool // Advanced vector extension 512 Vector Byte Manipulation Instructions 2HasAVX512BITALGbool // Advanced vector extension 512 Bit AlgorithmsHasAVX512BF16bool // Advanced vector extension 512 BFloat16 InstructionsHasAMXTilebool // Advanced Matrix Extension Tile instructionsHasAMXInt8bool // Advanced Matrix Extension Int8 instructionsHasAMXBF16bool // Advanced Matrix Extension BFloat16 instructionsHasBMI1bool // Bit manipulation instruction set 1HasBMI2bool // Bit manipulation instruction set 2HasCX16bool // Compare and exchange 16 BytesHasERMSbool // Enhanced REP for MOVSB and STOSBHasFMA bool // Fused-multiply-add instructionsHasOSXSAVEbool // OS supports XSAVE/XRESTOR for saving/restoring XMM registers.HasPCLMULQDQbool // PCLMULQDQ instruction - most often used GCMHasPOPCNTbool // Hamming weight instruction PsRDRANDbool // RDRAND instruction (on-chip rando generator)HasRDSEEDbool // RDSEED instruction (on-chip random number generator)HasSSE2bool // Streaming SIMD extension 2 (always available on amd64)HasSSE3bool // Streaming SIMD extension 3HasSSSE3bool // Supplemental streaming SIMD extension 3HasSSE41bool // Streaming SIMD extension 4 and 4.1HasSSE42bool // Streaming SIMD extension 4 and 4.2_CacheLinePad}// ARM64 contains the supported CPU features of the// current ARMv8(aarch64) platform. If the current platform// is not arm64 then all feature flags are false.var ARM64 struct {_CacheLinePadHasFPbool // Floating-point instruction set (always available)HasASIMDbool // Advanced SIMD (always available)HasEVTSTRM  bool // Event stream supportHasAESbool // AES hardware implementationHasPMULLbool // Polynomial multiplication instruction setHasSHA1bool // SHA1 hardware implementationHasSHA2bool // SHA2 hardware implementationHasCRC32bool // CRC32 hardware implementationHasATOMICS  bool // Atomic memory operation instruction setHasFPHPbool // Half precision floating-point instruction setHasASIMDHP  bool // Advanced SIMD half precision instruction setHasCPUIDbool // CPUID identification scheme registersHasASIMDRDM bool // Rounding double multiply add/subtract instruction setHasJSCVTbool // Javascript conversion from floating-point to integerHasFCMAbool // Floating-point multiplication and addition of complex numbersHasLRCPCbool // Release Consistent processor consistent supportHasDCPOPbool // Persistent memory supportHasSHA3bool // SHA3 hardware implementationHasSM3bool // SM3 hardware implementationHasSM4bool // SM4 hardware implementationHasASIMDDP  bool // Advanced SIMD double precision instruction setHasSHA512bool // SHA512 hardware implementationHasSVEbool // Scalable Vector ExtensionsHasASIMDFHM bool // Advanced SIMD multiplication FP16 to FP32_CacheLinePad}// ARM contains the supported CPU features of the current ARM (32-bit) platform.// All feature flags are false if://  1. the current platform is not arm, or//  2. the current operating system is not Linux.var ARM struct {_CacheLinePadHasSWPbool // SWP instruction supportHasHALFbool // Half-word load and store supportHasTHUMBbool // ARM Thumb instruction setHas26BITbool // Address space limited to 26-bitsHasFASTMUL  bool // 32-bit operand, 64-bit result multiplication supportHasFPAbool // Floating point arithmetic supportHasVFPbool // Vector floating point supportHasEDSPbool // DSP Extensions supportHasJAVAbool // Java instruction setHasIWMMXTbool // Intel Wireless MMX technology supportHasCRUNCHbool // MaverickCrunch context switching and handlingHasTHUMBEE  bool // Thumb EE instruction setHasNEONbool // NEON instruction setHasVFPv3bool // Vector floating point version 3 supportHasVFPv3D16 bool // Vector floating point version 3 D8-D15HasTLSbool // Thread local storage supportHasVFPv4bool // Vector floating point version 4 supportHasIDIVAbool // Integer divide instruction support in ARM modeHasIDIVTbool // Integer divide instruction support in Thumb modeHasVFPD32bool // Vector floating point version 3 D15-D31HasLPAEbool // Large Physical Address ExtensionsHasEVTSTRM  bool // Event stream supportHasAESbool // AES hardware implementationHasPMULLbool // Polynomial multiplication instruction setHasSHA1bool // SHA1 hardware implementationHasSHA2bool // SHA2 hardware implementationHasCRC32bool // CRC32 hardware implementation_CacheLinePad}// MIPS64X contains the supported CPU features of the current mips64/mips64le// platforms. If the current platform is not mips64/mips64le or the current// operating system is not Linux then all feature flags are false.var MIPS64X struct {_CacheLinePadHasMSA bool // MIPS SIMD architecture_CacheLinePad}// PPC64 contains the supported CPU features of the current ppc64/ppc64le platforms.// If the current platform is not ppc64/ppc64le then all feature flags are false.//// For ppc64/ppc64le, it is safe to check only for ISA level starting on ISA v3.00,// since there are no optional categories. There are some exceptions that also// require kernel support to work (DARN, SCV), so there are feature bits for// those as well. The struct is padded to avoid false sharing.var PPC64 struct {_CacheLinePadHasDARN  bool // Hardware random number geneequires kernel enablement)HasSCVbool // Syscall vectouires kernel enablement)IsPOWER8 bool // ISA v2.07 (POWEER9 bool // ISA v3.00 (POWER9), implies IsPOWER8_CacheLinePad}// S390X contains the supported CPU features of the IBM Z// (s390x) platform. If the current platform is not IBM Z // feature flags are false.//// S390X is padded to avoid false sFurther HasVX is only set// if the OS supports vector registers in addition to the STFLE// feature bit being set.var S390X struct {_ CacheLinePadHasZARCH  bool // z/Architecture mode is active [mandatory]  bool // store facility list extendedHasLDISP  bool // long (20-bit) dintsHasEIMMbool // 32-bit immediatesHasDFPbool // decimal floatingsETF3EH bool // ETF-3 enhancedHasMSAbool // message security assist (CPACF)HasAESbool // KM-AES{128,192,256} functionsHasAESCBC bool // KMC-AES{128,192,256} functionsHasAESCTR bool // KMCTR-AES{128,192,256} functionsHasAESGCM bool // KMA-GCM-AES{128,192,256} functionsHasGHASH  bool // KIMD-GHASH functionHasSHA1bool // K{I,L}MD-SHA-1 functionsHasSHA256 bool // K{I,L}MD-SHA-256 functionsHasSHA512 bool // K{I,L}MD-SHA-512 functionsHasSHA3bool // K{I,L}MD-SHA3-{224,256,384,512} and K{I,L}MD-SHAKE-{128,256} functionsHasVXbool // vector facilityHasVXEbool // vector-enhancements facility 1_ CacheLinePad} init() {archInit()initOptions()processOptions()}// options contaipu debug options that can be used in GODEBUG.// Options are arch dependent and a by the arch specific initOptions functions.// Features that are mandatory for tfic GOARCH should have the Required field set// (e.g. SSE2 on amd64).var options []option// Option names should be lower case. e.g. avx instead of AVX.type option struct {NamestringFeature*boolSpecified bool // whether feature value was specified in GODEBUGEnablebool // whether feature should be enabledRequired  bool // whether feature is mandatory and can not be disabled} processOptions() {env := os.Getenv("GODEBUG")field:for env != "" {field := ""i := strings.IndexByte(env, ',')if i < 0 {field, env = env, ""} else {field, env = env[:i], env[i+1:]}if len(field) < 4 || field[:4] != "cpu." {continue}i = strings.IndexByte(field, '=')if i < 0 {print("GODEBUG sys/cpu: no value specified for \"", field, "\"\n")continue}key, value := field[4:i], field[i+1:] // e.g. "SSE2", "on"var enable boolswitch value {case "on":enable = truecase "off":enable = falsedefault:print("GODEBUG sys/cpu: value \"", value, "\" not supported for cpu option \"", key, "\"\n")continue field}if key == "all" {for i := range options {options[i].Specified = trueoptions[i].Enable = enable || options[i].Required}continue field}for i := range options {if options[i].Name == key {options[i].Specified = trueoptions[i].Enable = enablecontinue field}}print("GODEBUG sys/cpu: unknown cpu feature \"", key, "\"\n")}for _, o := range options {if !o.Specified {continue}if o.Enable && !*o.Feature {print("GODEBUG sys/cpu: can not enable \"", o.Name, "\", missing CPU support\n")continue}if !o.Enable && o.Required {print("GODEBUG sys/cpu: can not disable \"", o.Name, "\", required CPU feature\n")continue}*o.Feature = o.Enable}}